import{_ as a,o as e,c as r,ac as o}from"./chunks/framework.RaldHO_f.js";const c=JSON.parse('{"title":"关于我","description":"Dongling Mo 的个人介绍","frontmatter":{"title":"关于我","description":"Dongling Mo 的个人介绍","layout":"doc","sidebar":false},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":null}'),i={name:"about.md"};function n(l,t,d,s,g,h){return e(),r("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1776490421167"},[...t[0]||(t[0]=[o('<div style="text-align:center;padding:2rem 0 1rem;"><img src="https://github.com/DonglingMo.png" alt="Dongling Mo" style="width:120px;border-radius:50%;border:3px solid var(--vp-c-brand-1);"><h1 style="margin-top:1rem;">Dongling Mo</h1><p style="color:var(--vp-c-text-2);font-size:1rem;">技术博主 · 软件工程师 · 终身学习者</p></div><h2 id="👋-你好" tabindex="-1">👋 你好 <a class="header-anchor" href="#👋-你好" aria-label="Permalink to &quot;👋 你好&quot;">​</a></h2><p>我是 Dongling Mo，一名对技术保持广泛好奇心的软件工程师。这个博客涵盖我日常探索的各个技术领域——从底层系统到 AI 应用，从架构设计到效率工具，只要是有趣的、有价值的，都值得写下来。</p><h2 id="🛠-技术栈" tabindex="-1">🛠 技术栈 <a class="header-anchor" href="#🛠-技术栈" aria-label="Permalink to &quot;🛠 技术栈&quot;">​</a></h2><table tabindex="0"><thead><tr><th>领域</th><th>技术</th></tr></thead><tbody><tr><td>后端</td><td>Go · Python · Node.js · Java</td></tr><tr><td>前端</td><td>Vue 3 · React · TypeScript</td></tr><tr><td>系统 &amp; 运维</td><td>Linux · Docker · K8s · Nginx</td></tr><tr><td>数据库</td><td>PostgreSQL · MySQL · Redis · MongoDB</td></tr><tr><td>AI &amp; 数据</td><td>LLM · LangChain · PyTorch · SQL</td></tr><tr><td>工程化</td><td>Git · CI/CD · GitHub Actions · Vite</td></tr></tbody></table><h2 id="📝-这里会写什么" tabindex="-1">📝 这里会写什么 <a class="header-anchor" href="#📝-这里会写什么" aria-label="Permalink to &quot;📝 这里会写什么&quot;">​</a></h2><ul><li><strong>系统设计</strong> —— 架构思考、分布式系统、性能调优</li><li><strong>后端开发</strong> —— 语言特性、框架实践、踩坑经验</li><li><strong>前端工程</strong> —— 现代框架、工程化工具、性能优化</li><li><strong>AI 与大模型</strong> —— 应用落地、提示工程、工具链</li><li><strong>工具与效率</strong> —— 开发环境、效率软件、自动化脚本</li><li><strong>学习笔记</strong> —— 读书摘要、课程精华、技术文档解读</li></ul><h2 id="💬-写作初衷" tabindex="-1">💬 写作初衷 <a class="header-anchor" href="#💬-写作初衷" aria-label="Permalink to &quot;💬 写作初衷&quot;">​</a></h2><blockquote><p>费曼技巧：把你学到的知识教给别人，是检验理解程度最好的方式。</p></blockquote><p>写作让我对技术的理解变得更扎实。每一篇文章都是一次逼迫自己真正弄懂某件事的机会。</p><h2 id="🔗-联系方式" tabindex="-1">🔗 联系方式 <a class="header-anchor" href="#🔗-联系方式" aria-label="Permalink to &quot;🔗 联系方式&quot;">​</a></h2><div style="display:flex;gap:1rem;flex-wrap:wrap;margin-top:1rem;"><p><a href="https://github.com/DonglingMo" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/GitHub-DonglingMo-181717?style=flat-square&amp;logo=github" alt="GitHub" loading="lazy"></a></p></div><hr><p><em>本博客使用 <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a> + <a href="https://theme.sugarat.top/" target="_blank" rel="noreferrer">@sugarat/theme</a> 构建，托管在 <a href="https://pages.github.com/" target="_blank" rel="noreferrer">GitHub Pages</a>。</em></p>',14)])])}const b=a(i,[["render",n]]);export{c as __pageData,b as default};
